/**
 * CategoryConfiguration entity with Zod validation
 *
 * Enhanced configuration management supporting the sophisticated 9-stage
 * classification pipeline with validation per SCORING_LOGIC.md tuning parameters.
 */

import { z } from 'zod';

/**
 * Main category configuration interface matching the sophisticated
 * processing_config structure from email-categorizer-config.json
 */
export interface CategoryConfiguration {
  version: string; // Semantic version
  lastModified: Date;
  hash: string; // Content hash for validation

  // Main processing configuration
  processing_config: ProcessingConfig;

  // Validation metadata
  schemaVersion: string;
  validationPassed: boolean;
  validationErrors: string[];

  // Runtime optimization
  compiledRules: CompiledRule[]; // Pre-compiled for performance
  attributeMatrix: AttributeInfluenceMatrix; // Pre-computed influence matrix
}

/**
 * Processing configuration matching the structure from SCORING_LOGIC.md
 */
export interface ProcessingConfig {
  version: number;
  taxonomy_notes: string;
  settings: ProcessingSettings;
  category_signals: Record<string, CategorySignals>;
  confidence_thresholds: ConfidenceThresholds;
  multi_label_policy: MultiLabelPolicy;
  domain_signal_overrides: DomainOverrides;
  domain_signal_resolution: DomainResolution;
  top_level_categories: Record<string, TopLevelCategory>;
  attributes: AttributeSystem;
  attribute_relevance: AttributeRelevanceMatrix;
  ai_prompts: AIPromptSystem;
  feature_extraction_schema: JSONSchema;
}

/**
 * Processing settings implementing all tuning parameters from SCORING_LOGIC.md
 */
export interface ProcessingSettings {
  initialization: {
    apply_hard_assertions: boolean;
    seed_category_scores: boolean;
  };
  rule_scoring: {
    use_lexical_patterns: boolean;
    apply_subtype_rules: boolean;
    bounded_aggregation: boolean;
  };
  attribute_processing: {
    detect_self_sent: boolean;
    resolve_domains: boolean;
    derive_context_flags: boolean;
  };
  attribute_influence: {
    apply_bonuses: boolean;
    apply_penalties: boolean;
    enforce_caps: boolean;
  };
  disambiguation: {
    pairwise_adjustments: boolean;
    confidence_gap_threshold: number;
  };
  multi_label_selection: {
    max_labels: number;
    min_secondary_confidence: number;
    allowed_combinations: string[];
  };
  ai_routing: {
    high_confidence_threshold: number;
    ai_required_threshold: number;
    skip_ai_conditions: string[];
  };
}

/**
 * Category signals for hard assertions and strong indicators
 */
export interface CategorySignals {
  hard_assertions: {
    from_domains_ref?: {
      source_group: string;
      confidence: string;
    };
    subject_prefixes?: string[];
    from_addresses?: string[];
  };
  strong_indicators: {
    from_domains_ref?: {
      source_group: string;
      confidence: string;
    };
    subject_contains?: string[];
    body_contains?: string[];
  };
  disambiguators?: {
    boost_if_present_attributes?: string[];
    suppress_if_body_contains?: string[];
    boost_if_absent_categories?: string[];
  };
}

/**
 * Confidence thresholds for classification decisions
 */
export interface ConfidenceThresholds {
  high_confidence: number;
  medium_confidence: number;
  low_confidence: number;
  ai_classification_required: number;
  manual_review_required: number;
  secondary_label_min_gap: number;
}

/**
 * Multi-label policy configuration
 */
export interface MultiLabelPolicy {
  max_top_level_labels: number;
  min_confidence_for_additional: number;
  min_delta_primary_secondary: number;
  allow_financial_actionable_copresence: boolean;
}

/**
 * Domain signal overrides for specific category behaviors
 */
export interface DomainOverrides {
  [category: string]: {
    hard_include: string[];
    hard_exclude: string[];
    strong_include: string[];
    strong_exclude: string[];
  };
}

/**
 * Domain resolution configuration
 */
export interface DomainResolution {
  mode: string; // "runtime_resolved"
  source: string; // "config/domain-sources.json"
  notes: string;
}

/**
 * Top-level category definition with subtypes and AI classification
 */
export interface TopLevelCategory {
  description: string;
  subtypes: Record<string, SubtypeDefinition>;
  ai_final_classification: {
    category_description: string;
    decision_criteria: string[];
    exclusion_criteria?: string[];
  };
}

/**
 * Subtype definition with rule-based classification
 */
export interface SubtypeDefinition {
  description: string;
  rule_based_classification?: {
    high_confidence?: RulePattern[];
    medium_confidence?: RulePattern[];
    low_confidence?: RulePattern[];
  };
  derived?: boolean;
  derivation_logic?: string;
}

/**
 * Rule pattern for rule-based classification
 */
export interface RulePattern {
  field: string; // "subject", "body", "from.address", etc.
  operation: string; // "contains_any", "starts_with", "ends_with", "regex_any", "exists"
  values?: string[];
  weight: number;
}

/**
 * Attribute system configuration
 */
export interface AttributeSystem {
  schema: Record<string, AttributeSchema>;
  detectors: AttributeDetector[];
  derived: Record<string, DerivedAttribute>;
  attribute_bonus_map: Record<string, Record<string, number>>;
}

export interface AttributeSchema {
  type: string; // "enum", "boolean"
  values?: string[]; // For enum types
  description: string;
}

export interface AttributeDetector {
  attribute: string;
  field: string;
  operation: string;
  values: string[];
}

export interface DerivedAttribute {
  logic: string;
  notes: string;
}

/**
 * Attribute relevance matrix implementing roles from SCORING_LOGIC.md
 */
export interface AttributeRelevanceMatrix {
  _roles_legend: {
    CORE: string;
    PRIMARY_BOOST: string;
    SECONDARY_BOOST: string;
    DISAMBIGUATOR: string;
    FILTER: string;
    STRUCTURAL: string;
    DERIVED_LINK: string;
    NEUTRAL: string;
  };
  [category: string]:
    | {
        category_roles: Record<string, AttributeRole>;
        subtypes?: Record<
          string,
          {
            roles: Record<string, AttributeRole>;
          }
        >;
      }
    | {
        CORE: string;
        PRIMARY_BOOST: string;
        SECONDARY_BOOST: string;
        DISAMBIGUATOR: string;
        FILTER: string;
        STRUCTURAL: string;
        DERIVED_LINK: string;
        NEUTRAL: string;
      }; // For _roles_legend
}

export type AttributeRole =
  | 'CORE'
  | 'PRIMARY_BOOST'
  | 'SECONDARY_BOOST'
  | 'DISAMBIGUATOR'
  | 'FILTER'
  | 'STRUCTURAL'
  | 'DERIVED_LINK'
  | 'NEUTRAL';

/**
 * AI prompt system configuration
 */
export interface AIPromptSystem {
  feature_extraction: {
    system_prompt: string[];
    user_prompt: string[];
  };
  final_classification: {
    system_prompt: string[];
    user_prompt: string[];
  };
}

/**
 * JSON schema for feature extraction
 */
export interface JSONSchema {
  type: string;
  properties: Record<string, JSONSchemaProperty>;
  required: string[];
}

export interface JSONSchemaProperty {
  type: string;
  description?: string;
  enum?: string[];
  items?: JSONSchemaProperty;
  properties?: Record<string, JSONSchemaProperty>;
  required?: string[];
}

/**
 * Pre-compiled rule for performance optimization
 */
export interface CompiledRule {
  category: string;
  subtype: string;
  tier: string;
  pattern: RegExp;
  weight: number;
}

/**
 * Pre-computed attribute influence matrix for performance
 */
export interface AttributeInfluenceMatrix {
  [category: string]: {
    [attribute: string]: {
      role: AttributeRole;
      bonus: number;
      cap: number;
    };
  };
}

