  adjustment_decay_factor?: number;
  enable_subtype_disambiguation?: boolean;
}

/**
 * Execute disambiguation stage
 *
 * Analyzes candidate scores to identify competing categories and applies
 * targeted adjustments using DISAMBIGUATOR attributes to resolve conflicts.
 */
export async function executeDisambiguation(
  email: EmailMessage,
  context: AttributeContext,
  config: CategoryConfiguration
): Promise<DisambiguationResult> {
  const startTime = Date.now();

  // Validate configuration
  if (!config.processing_config?.settings?.disambiguation) {
    throw new Error('Disambiguation configuration not found');
  }

  const disambiguationConfig = config.processing_config.settings.disambiguation;
  validateDisambiguationConfig(disambiguationConfig);

  // Extract candidate scores from email
  const emailData = email as EmailMessage & Record<string, unknown>;
  const candidateScores = (emailData.candidate_scores as Record<string, number>) || {};

  const originalScores = { ...candidateScores };
  const updatedScores = { ...candidateScores };

  // If no scores or insufficient scores, skip disambiguation
  if (Object.keys(candidateScores).length < 2) {
    return createEmptyResult(originalScores, updatedScores, disambiguationConfig, startTime, emailData);
  }

  // Identify competing categories
  const competingCategories = identifyCompetingCategories(candidateScores, disambiguationConfig);

  // Apply disambiguation adjustments
  const adjustmentsApplied: DisambiguationAdjustment[] = [];

  if (competingCategories.length > 0) {
    const adjustments = calculateDisambiguationAdjustments(competingCategories, context, config, disambiguationConfig);

    // Apply adjustments to scores
    for (const adjustment of adjustments) {
      updatedScores[adjustment.category] = (updatedScores[adjustment.category] || 0) + adjustment.adjustment_amount;
      adjustmentsApplied.push(adjustment);
    }
  }

  // Calculate score deltas
  const scoreDeltas: Record<string, number> = {};
  for (const category of Object.keys(originalScores)) {
    scoreDeltas[category] = (updatedScores[category] || 0) - (originalScores[category] || 0);
  }

  const processingDuration = Math.max(1, Date.now() - startTime);

  // Build result
  const result: DisambiguationResult = {
    competing_categories: competingCategories,
    adjustments_applied: adjustmentsApplied,
    original_scores: originalScores,
    updated_scores: updatedScores,
    score_deltas: scoreDeltas,
    processing_duration_ms: processingDuration,
    configuration_references: {
      disambiguation_settings_path: 'processing_config.settings.disambiguation',
      confidence_gap_threshold: disambiguationConfig.confidence_gap_threshold,
    },
  };

  // Preserve stage chain data
  if ('candidate_scores' in emailData) {
