  AttributeRole,
} from './category-config-schema';
import {
  ProcessingConfigTuning,
  validateProcessingConfigTuning,
  getProcessingConfigErrors,
} from './processing-config-schema';

/**
 * Configuration loader with hot-reload capability
 * Monitors configuration files for changes and validates them automatically
 */

export interface ConfigLoadOptions {
  configDir?: string;
  enableHotReload?: boolean;
  validateOnLoad?: boolean;
  compileRules?: boolean;
  cacheTtlMs?: number;
  backupOnChange?: boolean;
}

export interface ConfigLoadResult<T> {
  config: T;
  hash: string;
  lastModified: Date;
  validationPassed: boolean;
  validationErrors: string[];
  loadTime: number;
}

export interface CompiledRule {
  category: string;
  subtype: string;
  tier: 'high' | 'medium' | 'low';
  pattern: RegExp;
  weight: number;
  parallel_safe: boolean;
}

export interface AttributeInfluenceMatrix {
  [category: string]: {
    [attribute: string]: {
      role: AttributeRole;
      bonus: number;
      cap: number;
    };
  };
}

// eslint-disable-next-line @typescript-eslint/no-unsafe-declaration-merging
export class ConfigurationLoader extends EventEmitter {
  private configDir: string;
  private enableHotReload: boolean;
  private validateOnLoad: boolean;
  private compileRules: boolean;
  private cacheTtlMs: number;
  private backupOnChange: boolean;

  private watchers: Map<string, FSWatcher> = new Map();
  private configCache: Map<string, ConfigLoadResult<unknown>> = new Map();
  private lastHashes: Map<string, string> = new Map();

  constructor(options: ConfigLoadOptions = {}) {
    super();

    this.configDir = options.configDir || join(process.cwd(), 'config');
    this.enableHotReload = options.enableHotReload ?? true;
    this.validateOnLoad = options.validateOnLoad ?? true;
    this.compileRules = options.compileRules ?? true;
    this.cacheTtlMs = options.cacheTtlMs ?? 60000; // 1 minute default
    this.backupOnChange = options.backupOnChange ?? true;

    // Clean up watchers on process exit
    process.on('exit', () => this.cleanup());
    process.on('SIGINT', () => this.cleanup());
    process.on('SIGTERM', () => this.cleanup());
  }

  /**
   * Load category configuration with validation and hot-reload setup
   */
  async loadCategoryConfiguration(
    filename: string = 'email-categorizer-config.json'
  ): Promise<ConfigLoadResult<CategoryConfiguration>> {
    const filepath = join(this.configDir, filename);

    try {
      const startTime = Date.now();

      // Check cache first
      const cached = this.getCachedConfig<CategoryConfiguration>(filepath);
      if (cached) {
        return cached;
      }

      // Load and parse configuration
      const fileContent = await fs.readFile(filepath, 'utf-8');
      const hash = this.calculateHash(fileContent);
      const stats = await fs.stat(filepath);

      let config: unknown;
      try {
        config = JSON.parse(fileContent);
      } catch (parseError) {
        throw new Error(
          `Failed to parse JSON in ${filepath}: ${parseError instanceof Error ? parseError.message : String(parseError)}`
        );
      }

      // Validate configuration
      let validationPassed = true;
      let validationErrors: string[] = [];
      let validatedConfig: CategoryConfiguration;

      if (this.validateOnLoad) {
        try {
          validatedConfig = validateCategoryConfiguration(config);

          // Additional custom validation
          validationErrors = await this.validateCategoryConfigurationCustom(validatedConfig);
          validationPassed = validationErrors.length === 0;
        } catch (error) {
          console.error('Configuration validation failed:', error);
          validationPassed = false;
          validationErrors = getValidationErrors(config);
          validatedConfig = config as CategoryConfiguration; // Use unvalidated config for error reporting
        }
      } else {
        validatedConfig = config as CategoryConfiguration;
      }

      // Compile rules if enabled
      if (this.compileRules && validationPassed) {
        validatedConfig.compiledRules = await this.compileConfigurationRules(validatedConfig);
        validatedConfig.attributeMatrix = await this.computeAttributeMatrix(validatedConfig);
      }

      // Update metadata
      validatedConfig.hash = hash;
      validatedConfig.lastModified = stats.mtime;
      validatedConfig.validationPassed = validationPassed;
      validatedConfig.validationErrors = validationErrors;

      // Performance metrics
      if (!validatedConfig.performanceMetrics) {
        validatedConfig.performanceMetrics = {};
      }
      validatedConfig.performanceMetrics.last_validation_time_ms = Date.now() - startTime;

      const result: ConfigLoadResult<CategoryConfiguration> = {
        config: validatedConfig,
        hash,
        lastModified: stats.mtime,
        validationPassed,
        validationErrors,
        loadTime: Date.now() - startTime,
      };

      // Cache the result
      this.setCachedConfig(filepath, result);
      this.lastHashes.set(filepath, hash);

      // Set up hot-reload if enabled
      if (this.enableHotReload && !this.watchers.has(filepath)) {
        await this.setupHotReload(filepath, 'category');
      }

      // Create backup if enabled
      if (this.backupOnChange && validationPassed) {
        await this.createBackup(filepath, hash);
      }

      this.emit('configLoaded', { type: 'category', filepath, result });

      return result;
    } catch (error) {
      this.emit('configError', { type: 'category', filepath, error: error as Error });
      throw new Error(
        `Failed to load category configuration from ${filepath}: ${error instanceof Error ? error.message : String(error)}`
      );
    }
  }

  /**
   * Load processing configuration with validation
   */
  async loadProcessingConfiguration(
    filename: string = 'processing-config.json'
  ): Promise<ConfigLoadResult<ProcessingConfigTuning>> {
    const filepath = join(this.configDir, filename);

    try {
      const startTime = Date.now();

      // Check cache first
      const cached = this.getCachedConfig<ProcessingConfigTuning>(filepath);
      if (cached) {
        return cached;
      }

      // Load and parse configuration
      const fileContent = await fs.readFile(filepath, 'utf-8');
      const hash = this.calculateHash(fileContent);
      const stats = await fs.stat(filepath);

      let config: unknown;
      try {
        config = JSON.parse(fileContent);
      } catch (parseError) {
        throw new Error(
          `Failed to parse JSON in ${filepath}: ${parseError instanceof Error ? parseError.message : String(parseError)}`
        );
      }

      // Validate configuration
      let validationPassed = true;
      let validationErrors: string[] = [];
      let validatedConfig: ProcessingConfigTuning;

      if (this.validateOnLoad) {
        try {
          validatedConfig = validateProcessingConfigTuning(config);

          // Additional custom validation
          validationErrors = await this.validateProcessingConfigurationCustom(validatedConfig);
          validationPassed = validationErrors.length === 0;
        } catch (error) {
          console.error('Processing configuration validation failed:', error);
          validationPassed = false;
          validationErrors = getProcessingConfigErrors(config);
          validatedConfig = config as ProcessingConfigTuning; // Use unvalidated config for error reporting
        }
      } else {
        validatedConfig = config as ProcessingConfigTuning;
      }

      const result: ConfigLoadResult<ProcessingConfigTuning> = {
