/**
 * T033: Disambiguation Stage Implementation
 *
 * Resolves conflicts between competing categories by applying pairwise adjustments
 * when confidence gaps are below the threshold. Uses DISAMBIGUATOR attributes to
 * help resolve close classification decisions.
 *
 * Reference: DisambiguationNode.js (pairwise adjustments for competing categories)
 * Config: processing_config.settings.disambiguation.confidence_gap_threshold
 * Logic: Pairwise adjustments per SCORING_LOGIC.md "Disambiguation Stage"
 */

import { EmailMessage } from '../types/email-message';
import { AttributeContext } from '../types/attribute-context';
import { CategoryConfiguration, AttributeRole } from '../types/category-configuration';

/**
 * Result of disambiguation stage
 */
export interface DisambiguationResult {
  competing_categories: CompetingCategoryPair[];
  adjustments_applied: DisambiguationAdjustment[];
  original_scores: Record<string, number>;
  updated_scores: Record<string, number>;
  score_deltas: Record<string, number>;
  processing_duration_ms: number;
  configuration_references: {
    disambiguation_settings_path: string;
    confidence_gap_threshold: number;
  };
  // Preserve previous stage data
  [key: string]: unknown;
}

/**
 * Competing category pair requiring disambiguation
 */
export interface CompetingCategoryPair {
  category1: string;
  category2: string;
  score_gap: number;
  requires_disambiguation: boolean;
  subtype_competition?: boolean;
}

/**
 * Disambiguation adjustment applied to a category
 */
export interface DisambiguationAdjustment {
  category: string;
  attribute: string;
  role: AttributeRole;
  adjustment_amount: number;
  adjustment_reason: string;
  confidence_factor: number;
  decay_applied: boolean;
  decay_factor?: number;
}

/**
 * Disambiguation configuration
 */
interface DisambiguationConfig {
  pairwise_adjustments: boolean;
  confidence_gap_threshold: number;
  max_adjustments_per_email?: number;
  adjustment_decay_factor?: number;
  enable_subtype_disambiguation?: boolean;
}

/**
 * Execute disambiguation stage
 *
 * Analyzes candidate scores to identify competing categories and applies
 * targeted adjustments using DISAMBIGUATOR attributes to resolve conflicts.
 */
export async function executeDisambiguation(
  email: EmailMessage,
  context: AttributeContext,
  config: CategoryConfiguration
): Promise<DisambiguationResult> {
  const startTime = Date.now();

  // Validate configuration
  if (!config.processing_config?.settings?.disambiguation) {
    throw new Error('Disambiguation configuration not found');
  }

  const disambiguationConfig = config.processing_config.settings.disambiguation;
  validateDisambiguationConfig(disambiguationConfig);

  // Extract candidate scores from email
  const emailData = email as EmailMessage & Record<string, unknown>;
  const candidateScores = (emailData.candidate_scores as Record<string, number>) || {};

  const originalScores = { ...candidateScores };
  const updatedScores = { ...candidateScores };

  // If no scores or insufficient scores, skip disambiguation
  if (Object.keys(candidateScores).length < 2) {
    return createEmptyResult(originalScores, updatedScores, disambiguationConfig, startTime, emailData);
  }

  // Identify competing categories
  const competingCategories = identifyCompetingCategories(candidateScores, disambiguationConfig);

  // Apply disambiguation adjustments
  const adjustmentsApplied: DisambiguationAdjustment[] = [];

  if (competingCategories.length > 0) {
    const adjustments = calculateDisambiguationAdjustments(competingCategories, context, config, disambiguationConfig);

    // Apply adjustments to scores
    for (const adjustment of adjustments) {
      updatedScores[adjustment.category] = (updatedScores[adjustment.category] || 0) + adjustment.adjustment_amount;
      adjustmentsApplied.push(adjustment);
    }
  }

  // Calculate score deltas
  const scoreDeltas: Record<string, number> = {};
  for (const category of Object.keys(originalScores)) {
    scoreDeltas[category] = (updatedScores[category] || 0) - (originalScores[category] || 0);
  }

  const processingDuration = Math.max(1, Date.now() - startTime);

  // Build result
  const result: DisambiguationResult = {
    competing_categories: competingCategories,
    adjustments_applied: adjustmentsApplied,
    original_scores: originalScores,
    updated_scores: updatedScores,
    score_deltas: scoreDeltas,
    processing_duration_ms: processingDuration,
    configuration_references: {
      disambiguation_settings_path: 'processing_config.settings.disambiguation',
      confidence_gap_threshold: disambiguationConfig.confidence_gap_threshold,
    },
  };

  // Preserve stage chain data
  if ('candidate_scores' in emailData) {
    result.candidate_scores = updatedScores; // Update with new scores
  }
  if ('stage_results' in emailData && emailData.stage_results) {
    result.stage_results = {
      ...(emailData.stage_results as Record<string, unknown>),
      disambiguation: { completed: true },
    };
  }

  return result;
}

/**
 * Identify competing categories that require disambiguation
 */
function identifyCompetingCategories(
  candidateScores: Record<string, number>,
  config: DisambiguationConfig
): CompetingCategoryPair[] {
  const competingPairs: CompetingCategoryPair[] = [];
  const categories = Object.entries(candidateScores).sort(([, a], [, b]) => b - a); // Sort by score descending

  // Check all pairs for competition
  for (let i = 0; i < categories.length; i++) {
    for (let j = i + 1; j < categories.length; j++) {
      const [category1, score1] = categories[i];
      const [category2, score2] = categories[j];

      const scoreGap = Math.abs(score1 - score2);

      if (scoreGap <= config.confidence_gap_threshold) {
        const isSubtypeCompetition = areSubtypesOfSameCategory(category1, category2);

        // Skip subtype competition if disabled
        if (isSubtypeCompetition && !(config.enable_subtype_disambiguation ?? true)) {
          continue;
        }

        competingPairs.push({
          category1,
          category2,
          score_gap: scoreGap,
          requires_disambiguation: true,
          subtype_competition: isSubtypeCompetition,
        });
      }
    }
  }

  return competingPairs;
}

/**
 * Calculate disambiguation adjustments using DISAMBIGUATOR attributes
 */
function calculateDisambiguationAdjustments(
  competingCategories: CompetingCategoryPair[],
  context: AttributeContext,
  config: CategoryConfiguration,
  disambiguationConfig: DisambiguationConfig
): DisambiguationAdjustment[] {
  const adjustments: DisambiguationAdjustment[] = [];
  const categoryAdjustmentCounts: Record<string, number> = {};

  // Get all categories involved in competition
  const involvedCategories = new Set<string>();
  for (const pair of competingCategories) {
    involvedCategories.add(pair.category1);
    involvedCategories.add(pair.category2);
  }

  // Find DISAMBIGUATOR attributes for involved categories
  for (const [attributeName, metadata] of Object.entries(context.detectionMetadata)) {
    for (const categoryName of involvedCategories) {
      const categoryKey = getCategoryKey(categoryName);
      const subtypeKey = getSubtypeKey(categoryName);

      const attributeRole = getAttributeRole(attributeName, categoryKey, subtypeKey, config);

      if (attributeRole === 'DISAMBIGUATOR') {
        // Check if we've hit the adjustment limit
        if (adjustments.length >= (disambiguationConfig.max_adjustments_per_email || 10)) {
          break;
        }

        // Calculate adjustment amount
        const categoryAdjustmentCount = categoryAdjustmentCounts[categoryName] || 0;
        const decayFactor = Math.pow(disambiguationConfig.adjustment_decay_factor || 0.8, categoryAdjustmentCount);

        // Base adjustment proportional to confidence
        const baseAdjustment = 0.1 * metadata.confidence; // 10% max adjustment scaled by confidence
        const adjustmentAmount = baseAdjustment * decayFactor;

        adjustments.push({
          category: categoryName,
          attribute: attributeName,
          role: 'DISAMBIGUATOR',
          adjustment_amount: adjustmentAmount,
          adjustment_reason: 'disambiguator_bonus',
          confidence_factor: metadata.confidence,
          decay_applied: categoryAdjustmentCount > 0,
          decay_factor: categoryAdjustmentCount > 0 ? decayFactor : undefined,
        });

        categoryAdjustmentCounts[categoryName] = categoryAdjustmentCount + 1;
      }
    }

    // Break if we've hit the global limit
    if (adjustments.length >= (disambiguationConfig.max_adjustments_per_email || 10)) {
      break;
    }
  }

  return adjustments;
}

/**
 * Get attribute role for a category/subtype combination
 */
function getAttributeRole(
  attributeName: string,
  categoryKey: string,
  subtypeKey: string | null,
  config: CategoryConfiguration
): AttributeRole | null {
  const attributeRelevance = config.processing_config?.attribute_relevance;
  if (!attributeRelevance) return null;

  const categoryConfig = attributeRelevance[categoryKey];
  if (!categoryConfig) return null;

  // Check subtype-specific role first (handle discriminated union)
  if (subtypeKey && 'subtypes' in categoryConfig && categoryConfig.subtypes?.[subtypeKey]?.roles?.[attributeName]) {
    return categoryConfig.subtypes[subtypeKey].roles[attributeName];
  }

  // Check category-level role (handle discriminated union)
  if ('category_roles' in categoryConfig && categoryConfig.category_roles?.[attributeName]) {
    return categoryConfig.category_roles[attributeName];
  }

  return null;
}

/**
 * Extract category key from full category name (handles both "CATEGORY" and "CATEGORY.SUBTYPE")
 */
function getCategoryKey(fullCategoryName: string): string {
  return fullCategoryName.split('.')[0];
}

/**
 * Extract subtype key from full category name
 */
function getSubtypeKey(fullCategoryName: string): string | null {
  const parts = fullCategoryName.split('.');
  return parts.length > 1 ? parts[1] : null;
}

/**
 * Check if two categories are subtypes of the same parent category
 */
function areSubtypesOfSameCategory(category1: string, category2: string): boolean {
  const parent1 = getCategoryKey(category1);
  const parent2 = getCategoryKey(category2);

  // Both must have subtypes and same parent
  return category1.includes('.') && category2.includes('.') && parent1 === parent2;
}

/**
 * Validate disambiguation configuration
 */
function validateDisambiguationConfig(config: DisambiguationConfig): void {
  if (config.confidence_gap_threshold < 0 || config.confidence_gap_threshold > 1) {
    throw new Error('Invalid confidence gap threshold');
  }
  if (typeof config.pairwise_adjustments !== 'boolean') {
    throw new Error('Invalid pairwise_adjustments flag');
  }
}

/**
 * Create empty result for cases with no disambiguation needed
 */
function createEmptyResult(
  originalScores: Record<string, number>,
  updatedScores: Record<string, number>,
  config: DisambiguationConfig,
  startTime: number,
  emailData: EmailMessage & Record<string, unknown>
): DisambiguationResult {
  const processingDuration = Math.max(1, Date.now() - startTime);

  const result: DisambiguationResult = {
    competing_categories: [],
    adjustments_applied: [],
    original_scores: originalScores,
    updated_scores: updatedScores,
    score_deltas: {},
    processing_duration_ms: processingDuration,
    configuration_references: {
      disambiguation_settings_path: 'processing_config.settings.disambiguation',
      confidence_gap_threshold: config.confidence_gap_threshold,
    },
  };

  // Preserve stage chain data
  if ('candidate_scores' in emailData) {
    result.candidate_scores = updatedScores;
  }
  if ('stage_results' in emailData && emailData.stage_results) {
    result.stage_results = {
      ...(emailData.stage_results as Record<string, unknown>),
      disambiguation: { completed: true },
    };
  }

  return result;
}

