    //   // Check if adding this bonus would exceed the cap
    //   if (originalBonus > 0) {
    //     // Positive bonuses (normal case)
    //     if (runningTotal + originalBonus > cap) {
    //       adjustedBonus = Math.max(0, cap - runningTotal);
    //       capReached = true;
    //     }
    //   } else {
    //     // Negative bonuses (FILTER role)
    //     if (runningTotal + originalBonus < cap) {
    //       adjustedBonus = Math.min(0, cap - runningTotal);
    //       capReached = true;
    //     }
    //   }

    //   runningTotal += adjustedBonus;

    //   cappedApplications.push({
    //     ...app,
    //     bonus_applied: adjustedBonus,
    //     score_after: app.score_before + adjustedBonus,
    //     cap_reached: capReached,
    //     application_metadata: {
    //       ...app.application_metadata,
    //       cap_type: capReached ? 'role_cap' : 'no_cap',
    //     },
    //   });
    // }
  }

  return cappedApplications;
}

/**
 * Validate that a role is a valid AttributeRole
 */
function validateAttributeRole(role: string): asserts role is AttributeRole {
  const validRoles: AttributeRole[] = [
    'CORE',
    'PRIMARY_BOOST',
    'SECONDARY_BOOST',
    'DISAMBIGUATOR',
    'FILTER',
    'STRUCTURAL',
    'DERIVED_LINK',
    'NEUTRAL',
  ];

  if (!validRoles.includes(role as AttributeRole)) {
    throw new Error(`Invalid attribute role: ${role}`);
  }
}

